var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"오늘은 학회를 소탕하는 작전이라던데? 아디트야 님은 준비를 단단히 하라더군.","JPN":"今日は学会を掃討する作戦を行うそうだぜ？　きっちり準備しておけってアーディティヤ様がおっしゃってたぞ。","ENG":"I heard we'll start the operation to clear out the Society today. Miss Aditya said to prepare well.","TWN":"今天是剿滅學會的作戰吧？阿迪亞說要做好充分準備。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"그 녀석들은 무슨 짓을 벌일지 몰라. 아디트야 님이 명령하는 대로만 행동하라고.\xA0","JPN":"学会は何をしでかすかわからない連中だ。アーディティヤ様の命令通りに動けよ。\xA0","ENG":"You won't know what those bastards will do. So, just do as Miss Aditya orders you, okay?\xA0","TWN":"那些傢伙不知道會耍什麼手段，只要按照阿迪亞的命令行動就好。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"클리파 허수 에너지 밀도가 점점 상승하고 있어. 밖에 나가 있는 사람들이 위험해.","JPN":"クリファ虚数エネルギーの密度が上昇し続けている。くっ、外にいる皆が危険だ。","ENG":"Qlipha Imaginary Energy density is gradually increasing. The people out there are in danger.","TWN":"逆卡巴拉虛數能量密度正在逐漸上升。外面的人很危險。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"아디트야 님께 연락해! 이대로라면……!","JPN":"アーディティヤ様に連絡だ！　このままでは……！","ENG":"Contact Miss Aditya! If this continues...!","TWN":"通知阿迪亞！這樣下去的話……！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"어서 카멜롯에 지원 요청을! 도시 전체가 의식에 휘말린다!","JPN":"急いでキャメロットに支援要請を！　都市全体が儀式に巻き込まれる！","ENG":"Go request backup from Camelot! The entire city is caught up in the ritual!","TWN":"快請求卡梅羅戰隊的支援！整個城市都是儀式範圍！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"새로운 함선에 승선하신 소감이 어떠세요? 아디트야 님?","JPN":"新しい艦船に搭乗した感想はどうですか？　アーディティヤ様？","ENG":"How does it feel to be onboard a new ship, Miss Aditya?","TWN":"登上新艦船的感覺如何？阿迪亞？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"카운터가 된 뒤 갈 곳 없는 저를 받아주셔서 감사합니다. 아디트야 님.","JPN":"カウンターになってから、行く当てのなかった私を迎え入れてくださり、ありがとうございます。アーディティヤ様。","ENG":"Thank you for taking me in when I had no place to go after becoming a Counter, Miss Aditya.","TWN":"謝謝你接納在成為制裁者後無處可去的我，阿迪亞。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_ADMIN_NULL_NULL","text":{"KOREA":"저는 당신에게 구원받았습니다. 부디, 저에게 새 이름을 지어주세요.","JPN":"私はあなたに救われました。どうか、私に新しい名前をつけてください。","ENG":"You saved me. Please, give me a new name.","TWN":"我的命是你就的，請給我一個新的名字吧。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"현실에 침식체가 부상했습니다!","JPN":"現世に侵食体が浮上してきました！","ENG":"A C.O. emerged in the Normalside!","TWN":"現世中有侵蝕體出沒！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"야크샤가 좌표를 전달했습니다. 정화를 준비하겠습니다!","JPN":"ヤクシャーから座標が届きました！　浄化の準備を開始します！","ENG":"Yaksha has sent us the coordinates! Readying the purification!","TWN":"夜叉戰隊已經向我們傳送座標，準備淨化作戰！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"우리는 태양의 빛을 따라!","JPN":"私たちは太陽の光に従って！","ENG":"We follow the light of the sun!","TWN":"我們追隨著太陽的光芒！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"아디트야 님, 괜찮으세요?","JPN":"アーディティヤ様、大丈夫ですか？","ENG":"Miss Aditya, are you okay?!","TWN":"阿迪亞，你沒事吧？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"안색이 많이 안 좋군. 저 침식체, 가만히 우릴 지켜만 보고 있어.","JPN":"顔色が悪いな。それにしてもあの侵食体、じっと俺たちを見つめているぜ。","ENG":"You don't look so good. That C.O. is just watching us.","TWN":"你的臉色不太好。那隻侵蝕體只是在靜靜地看著我們。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"무언가 이상하다.","JPN":"嫌な感じがする……","ENG":"Something's strange.","TWN":"有點不太對勁。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리 전대는 세 명으로 구성되어 있지 않았어.","JPN":"我々の戦隊が三人だけなわけがない。","ENG":"Our division did not consist of just three people.","TWN":"……我們戰隊並不是只有三個人。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"또한 우리만 작전에 투입된 것도 아니지.","JPN":"我々だけが作戦に投入されるのもおかしい。","ENG":"Also, we weren't the only ones to be deployed in the operation.","TWN":"而且不僅僅是我們投入作戰。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"전대가…… 우리 전대가 모두 투입됐어. 하지만…….","JPN":"戦隊が……我々の戦隊は全員投入されたはずだ。しかし……","ENG":"The division... Everyone in our division was deployed. But...","TWN":"戰隊……戰隊的所有人都……但是……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그들의 얼굴, 이름…… 그리고 함께했던 기억이 없다.","JPN":"彼らの顔、名前……そして記憶がすべて消えた。","ENG":"Their faces, names... and even the memories we shared with them. I can't remember any of it.","TWN":"他們的長相、名字……以及一起度過的記憶，我一點都想不起來。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"나는 나를 찾아와 이름을 받길 원하는 모든 전대원들의 이름을 지어주고, 기억하고 있었어.","JPN":"私は名付けてほしいと頼んできた、すべての隊員の名前を覚えている。","ENG":"I named and remembered every member of the division who came to me and asked me to give them a name.","TWN":"所有來找我的戰隊員，我都有替他們取名字並且牢牢記住。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만 너희 둘을 포함한 어떤 이도…… 그들을 기억하지 못하고 있다.","JPN":"しかし、君たち2人を含め、誰一人として彼らのことを覚えていない。","ENG":"But I can't remember any of their names... even including you two.","TWN":"但是現在……包括你們兩個人……我誰也不記得。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"그렇다는 것은…….","JPN":"ということは……","ENG":"Which means...","TWN":"那就是說……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"<color=#ffd34c>정보 오염</color>이 일어났다는 건가?\xA0","JPN":"<color=#ffd34c>情報汚染</color>が起こっているのか？\xA0","ENG":"A <color=#ffd34c>data corruption</color> has occurred?\xA0","TWN":"是<color=#ffd34c>資訊污染</color>嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그래. 그리고 이 추측이 맞다면, 이 도시 역시…….","JPN":"ああ、そして、その予想がもし当たっていれば、この都市もまた……","ENG":"Yes. If my guess is correct, then this city is also...","TWN":"對。如果這個猜測沒錯，這座城市也……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"본래는 사람들이 살고 있었던 도시…… 라는 거군요.","JPN":"本来は人々が住んでいた所……ということになりますね。","ENG":"It was a city where... people used to live.","TWN":"原來也曾是有人居住的城市……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"속이 메스꺼워…….","JPN":"吐き気がする……","ENG":"I don't feel too good...","TWN":"我……我好難受……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"머리에서 목소리가 들려…… 하나가…… 돼야 해…….","JPN":"頭の中から声が聞こえる……一つに……なるんだ……","ENG":"I hear voices in my head... Must... become one...","TWN":"腦子裡有聲音……必須……合而為一……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그극<color=#ff3636>그그그극</color>사사사사사살<color=#ff3636>려. </color> 시작<b>되</b>었다.","JPN":"たた<color=#ff3636>たたたた</color>助けてええええ<color=#ff3636>。</color>始ま<b>っ</b>た。","ENG":"Grrr kg<color=#ff3636>gggh</color>. H-h-h-hel<color=#ff3636>p me.</color> Has st<b>arte</b>d.","TWN":"呃呃呃<color=#ff3636>呃呃</color>，救-救<color=#ff3636>救</color>我……<b>開始</b>。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>정화는</color> <color=#ff3636>이제</color> 시작<b>되</b>었다.","JPN":"<color=#ff3636>浄化は</color><color=#ff3636>これで</color>はじ<b>ま</b>った。","ENG":"<color=#ff3636>The purification</color> <color=#ff3636>has now</color> star<b>te</b>d.","TWN":"<color=#ff3636>現在</color><color=#ff3636>開始</color>淨化<b></b>。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"침식체가 내는 저 목소리들은…… 이 도시에 있던 사람들과 전대원들…….","JPN":"侵食体が出すあの声……この都市にいた人々と戦隊員たちの……","ENG":"The voices the C.O.s make... They are those of my division members and the people of this city...","TWN":"侵蝕體發出的那些聲音……是這座城市裡的居民和戰隊員們……"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"그럼 저 침식체의 정체를 대략적으로 유추할 수 있겠어.","JPN":"それらを総合して、あの侵食体の正体をなんとなく予想できる。","ENG":"Then, I can roughly infer what these C.O.s are.","TWN":"那我們大概可以推測出那個侵蝕體的真面目。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"정보 말소 현상을 일으키는 침식체라면…… 역시 파편인가?","JPN":"情報抹消を引き起こす侵食体ということは……やはり破片か？","ENG":"If it's a C.O. that can erase information... then it is a Fragment?","TWN":"如果是能引起資訊污染的侵蝕體……果然是碎片嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"클리파 에너지의 파편이든, 인간 반죽이든 놈이 이 사건의 주범이라는 것엔 변함이 없다.","JPN":"クリファエネルギーの破片だろうと、人間の塊だろうと、この事件の元凶であることに変わりはない。","ENG":"Whether it's a Fragment of Qlipha Energy or human paste, it doesn't change the fact that it is the culprit.","TWN":"不管是逆卡巴拉的碎片，還是人類的殘骸，這傢伙都是這起事件的罪魁禍首。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"전원 정화 준비.","JPN":"全員、浄化作戦の準備を。","ENG":"Everyone, get ready to purify.","TWN":"全員準備淨化。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"정화 목표는 타입 미상의 거대 침식체.","JPN":"浄化のターゲットはタイプ不明の巨大侵食体だ。","ENG":"The purification target is a colossal C.O. of an unknown type.","TWN":"淨化目標為類型不明的巨型侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"현실에 나타나 영향을 끼치는 이상, 우리는 놈을 정화해야 한다.","JPN":"現実に現れ、影響を及ぼしている以上、我々は奴を浄化しなければならない。","ENG":"Since it has appeared in the Normalside and affected it, we must purify it.","TWN":"既然它出現在現世中並已經產生異常，就必須受到淨化。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리가 싸우기 적합한 상황이 아니란 것을 안다. 하지만 우리는 그럼에도, 나아가야 해.","JPN":"この戦いは我々に圧倒的不利であることは承知している。しかし、それでも我々は進まなければならん。","ENG":"I'm aware we are not in a suitable position to fight. Yet, we must go forth.","TWN":"我知道這種情況不適合我們戰鬥。但即便如此，我們也必須前進。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"모두들, 미안하다.","JPN":"皆、すまない。","ENG":"I'm sorry, everyone.","TWN":"各位，我很對不起。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"특히 너에게 미안하군. 라비. 딸과 둘이서 여행을 다니고 있지 않았나?","JPN":"特に君には申し訳ないと思っている。ラビ。娘と二人で旅をしているのだろう？","ENG":"Especially to you, Ravi. Didn't you say you wanted to go traveling with your daughter?","TWN":"特別是你，拉維。你還在和女兒一起旅行……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지……?","JPN":"お父さん……？","ENG":"Father...?","TWN":"爸爸……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"좋은 아빠는 애초에 아내를 잃은 시점에서 글렀어. 대신 좋은 물건을 남겨두고 왔지.","JPN":"いい父親になるのは、妻を失った時点で望めなくなった。その代わり、いいものを残してきた。","ENG":"I failed at being a good father the moment I lost my wife. So instead, I left her something nice.","TWN":"從一開始失去妻子的那一刻起，我就註定不會是個好爸爸。不過，我給她留了些東西。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"침식 재난이 일어났을 때, 더 빨리 달려갔어야 했어.","JPN":"侵食災害が起きた時、もっと早く駆け付けるべきだった。","ENG":"When the Corruption Disaster hit, I should've rushed over faster.","TWN":"侵蝕災難發生時，我明明應該再跑快一點的。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"엄마를 잃은 그 아이에게 더 많은 곳을 구경시켜주고, 더 많은 경험을 하게 해주고 싶었는데…….","JPN":"母親を失ったあの子に、もっとたくさんの場所に連れていき、たくさんのことを経験させてやりたかったが……","ENG":"I wanted to show my kid more places and let her experience new things after her mother's death...","TWN":"我本想帶著那個失去媽媽的孩子去更多地方看看，讓她有更多的經歷……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"마지막에 얼굴이라도 보고 와서 다행이야. 그 아이가 날 기억해줄진 모르겠지만.","JPN":"最後に顔を見てきてよかった。あの子が俺のことを覚えてくれるかはわからないが。","ENG":"But at least I got to see her face for one last time. Even if she might not be able to remember me.","TWN":"不過幸好有跟她見到最後一面。雖然不知道她是否會記得我。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"눈앞의 어둠을 정화한다.","JPN":"目の前の闇を浄化する。","ENG":"We purify the darkness before our eyes.","TWN":"淨化眼前的黑暗。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리는 숭고한 임무를 갖고 앞으로 갈 뿐이야. 후회할 리 없지.","JPN":"我々は崇高な任務を遂行するために進み続ける。後悔なんかあるわけがない。","ENG":"And go forth with our noble mission. There is no regret here.","TWN":"我們肩負著崇高的使命前進，絕不會感到後悔。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그러니 미안해할 필요 없다.","JPN":"だから申し訳ないなどと思わなくていい。","ENG":"So, you don't need to be sorry.","TWN":"所以不用道歉。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"나는 아샤의 내일을 위해 이 한 몸 불사를 뿐이니까.","JPN":"俺はアーシャの明日のために、この身を捧げるだけだ。","ENG":"I am merely risking my life so Asha's future can be bright.","TWN":"我是為了阿莎的明天而燃燒自己的。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"우리는 태양의 빛을 따라.","JPN":"私たちは太陽の光に従って。","ENG":"We follow the light of the sun.","TWN":"我們追隨太陽的光芒。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…… ","JPN":"…… ","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"삿된 것을 정화한다.","JPN":"邪なものを浄化する。","ENG":"And purify the evil.","TWN":"開始淨化邪惡。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_CA_SURYA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};